<?php
namespace App\Support\BugInvestigator\Rules;
use App\Models\PreinvoiceOrder; use Illuminate\Support\Facades\Schema;
class ProformaWorkflowRules { public function run(?int $id=null): array { $f=[];$b=[]; if(!Schema::hasTable('preinvoice_orders')) return [['table preinvoice_orders not found'],[]]; $q=PreinvoiceOrder::query()->withCount('items')->withCount('invoice'); if($id)$q->whereKey($id); foreach($q->latest()->limit($id?1:50)->get() as $p){ if($p->status===PreinvoiceOrder::STATUS_CONVERTED_TO_INVOICE && $p->invoice_count<1)$b[]="پیش‌فاکتور #{$p->id} تبدیل‌شده است ولی فاکتور ندارد."; if($p->invoice_count>1)$b[]="پیش‌فاکتور #{$p->id} بیش از یک فاکتور دارد."; if(in_array($p->status,[PreinvoiceOrder::STATUS_FINANCE_REVIEWING,PreinvoiceOrder::STATUS_CONVERTED_TO_INVOICE],true)&&!$p->warehouse_reviewed_at)$b[]="پیش‌فاکتور #{$p->id} قبل از ثبت تایید انبار وارد مرحله مالی/فاکتور شده است."; if($p->items_count<1)$f[]="پیش‌فاکتور #{$p->id} آیتم ندارد."; } return [$f,$b]; } }
